// Search endpoint - POST /search/:index
app.post('/search/:index', async (req, res) => {
  try {
    const { index } = req.params;
    const { query, from, size, sort, _source, aggs, highlight } = req.body;

    // Validate index name to prevent injection
    if (!isValidIndexName(index)) {
      return res.status(400).json({ error: 'Invalid index name' });
    }

    // Validate that a query is provided
    if (!query) {
      return res.status(400).json({ error: 'Query DSL is required in request body under "query" field' });
    }

    // Cap the size to prevent overly large result sets
    const maxSize = 10000;
    const requestedSize = size || 10;
    const safeSize = Math.min(requestedSize, maxSize);

    const searchParams = {
      index: index,
      body: {
        query: query,
        from: from || 0,
        size: safeSize
      }
    };

    // Add optional parameters if provided
    if (sort) {
      searchParams.body.sort = sort;
    }

    if (_source) {
      searchParams.body._source = _source;
    }

    if (aggs) {
      searchParams.body.aggs = aggs;
    }

    if (highlight) {
      searchParams.body.highlight = highlight;
    }

    const result = await esClient.search(searchParams);

    res.json({
      took: result.took,
      timed_out: result.timed_out,
      total: result.hits.total,
      hits: result.hits.hits,
      aggregations: result.aggregations || null,
      max_score: result.hits.max_score
    });
  } catch (error) {
    const statusCode = error.meta?.statusCode || 500;
    res.status(statusCode).json({
      error: error.message,
      details: error.meta?.body?.error || null
    });
  }
});

