// Validation helpers
function isValidIndexName(name) {
  if (!name || typeof name !== 'string') return false;
  // Prevent directory traversal and special characters
  if (name.includes('..') || name.includes('/') || name.includes('\\')) return false;
  // Elasticsearch index naming rules
  const validPattern = /^[a-z0-9][a-z0-9._\-*]*$/;
  return validPattern.test(name) && name.length <= 255;
}

function isValidIndexPattern(pattern) {
  if (!pattern || typeof pattern !== 'string') return false;
  if (pattern.includes('..') || pattern.includes('/') || pattern.includes('\\')) return false;
  // Allow wildcards and commas for multi-index patterns
  const validPattern = /^[a-z0-9*][a-z0-9._\-*,]*$/;
  return validPattern.test(pattern) && pattern.length <= 1024;
}

